import os

def delete_uploaded_file(filename):
    directory = 'uploads'
    file_path = os.path.join(directory, filename)
    
    if os.path.exists(file_path):
        os.remove(file_path)
        return f"{filename} has been deleted successfully."
    else:
        return f"File {filename} does not exist in the 'uploads' directory."